    -- By definition of Bernoulli distribution, the measure of the set {ω | i ∈ X ω} is p, and similarly for j.
    have h_measure : ∀ k ∈ u, P {ω | k ∈ X ω} = toNNReal p := by
      intro k hk
      have h_measure : P {ω | k ∈ X ω} = (infinitePi (fun a => toNNReal p • dirac (a ∈ u) + toNNReal (σ p) • dirac False)) {f : ι → Prop | f k = True} := by
        convert congr_arg ( fun μ => μ { s : Set ι | k ∈ s } ) hX.map_eq using 1;
        · rw [ MeasureTheory.Measure.map_apply_of_aemeasurable ] ; aesop;
          · exact hX.aemeasurable;
          · exact?;
        · rw [ bernoulliOn_apply' ];
          congr with f ; aesop;
      have h_measure : (infinitePi (fun a => toNNReal p • dirac (a ∈ u) + toNNReal (σ p) • dirac False)) {f : ι → Prop | f k = True} = (toNNReal p • dirac (k ∈ u) + toNNReal (σ p) • dirac False) {True} := by
        have h_measure : (infinitePi (fun a => toNNReal p • dirac (a ∈ u) + toNNReal (σ p) • dirac False)) {f : ι → Prop | f k = True} = (Measure.map (fun f => f k) (infinitePi (fun a => toNNReal p • dirac (a ∈ u) + toNNReal (σ p) • dirac False))) {True} := by
          rw [ Measure.map_apply ] <;> norm_num [ Set.preimage ];
          exact measurable_pi_apply k;
        rw [ h_measure, infinitePi_map_eval ];
      simp_all +decide [ setOf ];
      simp +decide [ ENNReal.smul_def ];
    ext s hs;
    by_cases h : True ∈ s <;> by_cases h' : False ∈ s <;> simp_all +decide [ Set.preimage ];
    · rw [ Measure.map_apply_of_aemeasurable, Measure.map_apply_of_aemeasurable ] <;> norm_num [ h, h' ];
      · rw [ show ( fun ω => i ∈ X ω ) ⁻¹' s = Set.univ from by ext ω; by_cases hi : i ∈ X ω <;> aesop, show ( fun ω => j ∈ X ω ) ⁻¹' s = Set.univ from by ext ω; by_cases hj : j ∈ X ω <;> aesop ];
      · fun_prop;
      · fun_prop;
    · rw [ Measure.map_apply_of_aemeasurable, Measure.map_apply_of_aemeasurable ] <;> norm_num [ h, h', h_measure i hi, h_measure j hj ];
      · convert h_measure i hi using 1;
        · congr with ω ; by_cases hi : i ∈ X ω <;> aesop;
        · convert h_measure j hj using 1;
          congr with ω ; by_cases hj : j ∈ X ω <;> aesop;
      · fun_prop;
      · fun_prop;
    · rw [ Measure.map_apply_of_aemeasurable, Measure.map_apply_of_aemeasurable ] <;> norm_num [ h, h' ];
      · rw [ show ( fun ω => i ∈ X ω ) ⁻¹' s = { ω | i ∈ X ω }ᶜ from ?_, show ( fun ω => j ∈ X ω ) ⁻¹' s = { ω | j ∈ X ω }ᶜ from ?_ ];
        · rw [ show { ω | i ∈ X ω }ᶜ = ( Set.univ \ { ω | i ∈ X ω } ) by ext; simp +decide, show { ω | j ∈ X ω }ᶜ = ( Set.univ \ { ω | j ∈ X ω } ) by ext; simp +decide, MeasureTheory.measure_diff, MeasureTheory.measure_diff ] <;> norm_num [ h_measure i hi, h_measure j hj ];
          · have := hX.aemeasurable;
            have := this.nullMeasurable ( show MeasurableSet { s : Set ι | j ∈ s } from ?_ ) ; aesop;
            exact?;
          · have := hX.aemeasurable;
            have := this.nullMeasurable ( show MeasurableSet { s : Set ι | i ∈ s } from ?_ );
            · exact this;
            · exact?;
        · ext ω; by_cases h'' : j ∈ X ω <;> aesop;
        · grind;
      · have := hX.aemeasurable;
        exact Measurable.aemeasurable ( measurableSet_mem ( j : ι ) |> MeasurableSet.mem ) |> fun h => h.comp_aemeasurable this;
      · fun_prop;
    · rw [ MeasureTheory.Measure.map_apply_of_aemeasurable, MeasureTheory.Measure.map_apply_of_aemeasurable ] <;> norm_num [ h, h' ];
      · rw [ show ( fun ω => i ∈ X ω ) ⁻¹' s = ∅ by ext ω; by_cases hi : i ∈ X ω <;> aesop, show ( fun ω => j ∈ X ω ) ⁻¹' s = ∅ by ext ω; by_cases hj : j ∈ X ω <;> aesop ];
      · have h_aemeasurable : AEMeasurable (fun ω => X ω) P := by
          exact?;
        exact Measurable.aemeasurable ( measurableSet_mem j |> MeasurableSet.mem ) |> fun h => h.comp_aemeasurable h_aemeasurable;
      · have := hX.aemeasurable;
        exact?

